mapper.select:
SELECT id, neighbourhood_cleansed, avg_price, min_price, max_price, house_count
FROM region_avg_price


        AND neighbourhood_cleansed LIKE CONCAT('%', #{param.keyword}, '%')


        AND neighbourhood_cleansed LIKE CONCAT('%', #{param.neighbourhoodCleansed}, '%')


        AND avg_price = #{param.avgPrice}


        AND min_price = #{param.minPrice}


        AND max_price = #{param.maxPrice}


        AND house_count = #{param.houseCount}


ORDER BY avg_price DESC, id DESC
